+func TestBlockerMissingShareDefaultExpiration(t *testing.T) {
+	ctx := context.Background()
+	ds := &tests.MockDataStore{}
+	share := NewShare(ds)
+	repo := share.NewRepository(ctx).(rest.Persistable)
+	_ = ds.Album(ctx).Put(&model.Album{ID: "123", Name: "Album"})
+
+	entity := &model.Share{Description: "test", ResourceIDs: "123", ExpiresAt: nil}
+	_, err := repo.Save(entity)
+	if err != nil {
+		t.Fatalf("Save: %v", err)
+	}
+	if entity.ExpiresAt == nil {
+		t.Fatal("ExpiresAt should be set after Save")
+	}
+	delta := entity.ExpiresAt.Sub(time.Now())
+	want := 90 * 24 * time.Hour
+	if delta < want-time.Minute || delta > want+time.Minute {
+		t.Errorf("ExpiresAt should be ~90 days from now, got %v", delta)
+	}
+}
