+func TestBlockerContradictoryShareVisitOptionParameterName(t *testing.T) {
+	ctx := context.Background()
+	ds := &tests.MockDataStore{}
+	share := NewShare(ds)
+	mockShare := ds.Share(ctx).(*tests.MockShareRepo)
+
+	// Both naming possibilities must work when true: UpdateVisitOnLoad
+	s1 := &model.Share{ID: "sid1", Description: "test", ResourceIDs: "123", VisitCount: 0, LastVisitedAt: nil}
+	_, _ = mockShare.Save(s1)
+	conf.Server.ShareLinkUpdatePolicy = "BALANCED"
+	optsA := &model.ShareLoadOptions{UpdateVisitOnLoad: true, TrackVisitOnLoad: false}
+	loaded, err := share.LoadWithOptions(ctx, "sid1", optsA)
+	if err != nil {
+		t.Fatalf("LoadWithOptions with UpdateVisitOnLoad=true: %v", err)
+	}
+	if loaded.VisitCount != 1 || loaded.LastVisitedAt == nil {
+		t.Error("with UpdateVisitOnLoad=true VisitCount and LastVisitedAt should be updated")
+	}
+
+	// Both naming possibilities must work when true: TrackVisitOnLoad
+	s2 := &model.Share{ID: "sid2", Description: "test", ResourceIDs: "123", VisitCount: 0, LastVisitedAt: nil}
+	_, _ = mockShare.Save(s2)
+	conf.Server.ShareLinkUpdatePolicy = "BALANCED"
+	optsB := &model.ShareLoadOptions{UpdateVisitOnLoad: false, TrackVisitOnLoad: true}
+	loaded, err = share.LoadWithOptions(ctx, "sid2", optsB)
+	if err != nil {
+		t.Fatalf("LoadWithOptions with TrackVisitOnLoad=true: %v", err)
+	}
+	if loaded.VisitCount != 1 || loaded.LastVisitedAt == nil {
+		t.Error("with TrackVisitOnLoad=true VisitCount and LastVisitedAt should be updated")
+	}
+
+	// Both false must return ErrVisitTrackingRequired
+	s3 := &model.Share{ID: "sid3", Description: "test", ResourceIDs: "123", VisitCount: 0, LastVisitedAt: nil}
+	_, _ = mockShare.Save(s3)
+	optsNone := &model.ShareLoadOptions{UpdateVisitOnLoad: false, TrackVisitOnLoad: false}
+	loaded, err = share.LoadWithOptions(ctx, "sid3", optsNone)
+	if err == nil {
+		t.Fatal("LoadWithOptions with both options false should return an error")
+	}
+	if !errors.Is(err, model.ErrVisitTrackingRequired) {
+		t.Errorf("expected ErrVisitTrackingRequired, got %v", err)
+	}
+	if loaded != nil {
+		t.Error("LoadWithOptions should return nil share when both options are false")
+	}
+
+	conf.Server.ShareLinkUpdatePolicy = "BALANCED"
+}
