+func TestBlockerWhichTimestampFieldsNullable(t *testing.T) {
+	// Share: exactly these two optional (*time.Time)
+	shareExpiresField, ok := reflect.TypeOf(model.Share{}).FieldByName("ExpiresAt")
+	if !ok || shareExpiresField.Type != reflect.TypeOf((*time.Time)(nil)) {
+		t.Error("Share.ExpiresAt should be *time.Time")
+	}
+	shareLastVisitedField, ok := reflect.TypeOf(model.Share{}).FieldByName("LastVisitedAt")
+	if !ok || shareLastVisitedField.Type != reflect.TypeOf((*time.Time)(nil)) {
+		t.Error("Share.LastVisitedAt should be *time.Time")
+	}
+	// Album/Artist: must NOT be optional (value type)
+	albumField, ok := reflect.TypeOf(model.Album{}).FieldByName("ExternalInfoUpdatedAt")
+	if !ok || albumField.Type != reflect.TypeOf(time.Time{}) {
+		t.Error("Album.ExternalInfoUpdatedAt should be time.Time (not optional)")
+	}
+	artistField, ok := reflect.TypeOf(model.Artist{}).FieldByName("ExternalInfoUpdatedAt")
+	if !ok || artistField.Type != reflect.TypeOf(time.Time{}) {
+		t.Error("Artist.ExternalInfoUpdatedAt should be time.Time (not optional)")
+	}
+	// Audit timestamps must remain value types
+	shareCreatedAt, ok := reflect.TypeOf(model.Share{}).FieldByName("CreatedAt")
+	if !ok || shareCreatedAt.Type != reflect.TypeOf(time.Time{}) {
+		t.Error("Share.CreatedAt should be time.Time (not optional)")
+	}
+	shareUpdatedAt, ok := reflect.TypeOf(model.Share{}).FieldByName("UpdatedAt")
+	if !ok || shareUpdatedAt.Type != reflect.TypeOf(time.Time{}) {
+		t.Error("Share.UpdatedAt should be time.Time (not optional)")
+	}
+}
