+func TestBlockerShareLinkUpdatePolicy(t *testing.T) {
+	ctx := context.Background()
+	ds := &tests.MockDataStore{}
+	share := NewShare(ds)
+	mockShare := ds.Share(ctx).(*tests.MockShareRepo)
+
+	// Put a share with VisitCount=0, LastVisitedAt=nil
+	s := &model.Share{ID: "sid", Description: "test", ResourceIDs: "123", VisitCount: 0, LastVisitedAt: nil}
+	_, _ = mockShare.Save(s)
+
+	// FAST: must update LastVisitedAt and VisitCount
+	conf.Server.ShareLinkUpdatePolicy = "FAST"
+	loaded, err := share.Load(ctx, "sid")
+	if err != nil {
+		t.Fatalf("Load: %v", err)
+	}
+	if loaded.VisitCount != 1 {
+		t.Errorf("with FAST policy VisitCount should be 1, got %d", loaded.VisitCount)
+	}
+	if loaded.LastVisitedAt == nil {
+		t.Error("with FAST policy LastVisitedAt should be set")
+	}
+
+	// Reset share for next case: VisitCount=0 again
+	s.VisitCount = 0
+	s.LastVisitedAt = nil
+	mockShare.Entity = s
+
+	// BALANCED: must update
+	conf.Server.ShareLinkUpdatePolicy = "BALANCED"
+	loaded, err = share.Load(ctx, "sid")
+	if err != nil {
+		t.Fatalf("Load: %v", err)
+	}
+	if loaded.VisitCount != 1 {
+		t.Errorf("with BALANCED policy VisitCount should be 1, got %d", loaded.VisitCount)
+	}
+	if loaded.LastVisitedAt == nil {
+		t.Error("with BALANCED policy LastVisitedAt should be set")
+	}
+
+	// Reset share
+	s.VisitCount = 0
+	s.LastVisitedAt = nil
+	mockShare.Entity = s
+
+	// THOROUGH: must NOT update
+	conf.Server.ShareLinkUpdatePolicy = "THOROUGH"
+	loaded, err = share.Load(ctx, "sid")
+	if err != nil {
+		t.Fatalf("Load: %v", err)
+	}
+	if loaded.VisitCount != 0 {
+		t.Errorf("with THOROUGH policy VisitCount should remain 0, got %d", loaded.VisitCount)
+	}
+	if loaded.LastVisitedAt != nil {
+		t.Error("with THOROUGH policy LastVisitedAt should not be set")
+	}
+
+	// Restore default
+	conf.Server.ShareLinkUpdatePolicy = "BALANCED"
+}
