@@ -44,3 +44,27 @@ func (m *MockShareRepo) Exists(id string) (bool, error) {
 	}
 	return id == m.ID, nil
 }
+
+func (m *MockShareRepo) Get(id string) (*model.Share, error) {
+	if m.Error != nil {
+		return nil, m.Error
+	}
+	if m.Entity != nil {
+		if s, ok := m.Entity.(*model.Share); ok && s.ID == id {
+			return s, nil
+		}
+	}
+	return &model.Share{ID: id}, nil
+}
+
+func (m *MockShareRepo) GetAll(...model.QueryOptions) (model.Shares, error) {
+	if m.Error != nil {
+		return nil, m.Error
+	}
+	if m.Entity != nil {
+		if s, ok := m.Entity.(*model.Share); ok {
+			return model.Shares{*s}, nil
+		}
+	}
+	return nil, nil
+}
